import React, { useState, useEffect } from 'react';
import styled from 'styled-components';
import { useNavigate } from 'react-router-dom';
import { FaUser, FaEdit, FaSave, FaTimes } from 'react-icons/fa';
import { useAuth } from '../../hooks/useAuth';
import movieService from '../../services/movieService';

const Profile = () => {
  const { user, updateProfile, logout } = useAuth();
  const navigate = useNavigate();

  const [isEditing, setIsEditing] = useState(false);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    password: '',
    confirmPassword: ''
  });
  const [error, setError] = useState(null);
  const [success, setSuccess] = useState(null);
  const [ratedMovies, setRatedMovies] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (user) {
      setFormData({
        name: user.name || '',
        email: user.email || '',
        password: '',
        confirmPassword: ''
      });

      // Fetch user's rated movies
      const fetchRatedMovies = async () => {
        try {
          setLoading(true);
          const data = await movieService.getRatedMovies();
          setRatedMovies(data);
        } catch (err) {
          console.error('Error fetching rated movies:', err);
        } finally {
          setLoading(false);
        }
      };

      fetchRatedMovies();
    }
  }, [user]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError(null);
    setSuccess(null);

    // Validate passwords match if changing password
    if (formData.password && formData.password !== formData.confirmPassword) {
      setError('Passwords do not match');
      return;
    }

    try {
      // Only send fields that have values
      const updateData = {};
      if (formData.name) updateData.name = formData.name;
      if (formData.email) updateData.email = formData.email;
      if (formData.password) updateData.password = formData.password;

      await updateProfile(updateData);
      setSuccess('Profile updated successfully');
      setIsEditing(false);

      // Clear password fields after successful update
      setFormData(prev => ({
        ...prev,
        password: '',
        confirmPassword: ''
      }));
    } catch (err) {
      setError(err.message || 'Failed to update profile');
    }
  };

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  return (
    <ProfileContainer>
      <ProfileHeader>
        <ProfileTitle>My Profile</ProfileTitle>
        <LogoutButton onClick={handleLogout}>Logout</LogoutButton>
      </ProfileHeader>

      <ProfileContent>
        <ProfileSection>
          <SectionTitle>
            Account Information
            {!isEditing ? (
              <EditButton onClick={() => setIsEditing(true)}>
                <FaEdit /> Edit
              </EditButton>
            ) : (
              <CancelButton onClick={() => {
                setIsEditing(false);
                setError(null);
                // Reset form data to user data
                if (user) {
                  setFormData({
                    name: user.name || '',
                    email: user.email || '',
                    password: '',
                    confirmPassword: ''
                  });
                }
              }}>
                <FaTimes /> Cancel
              </CancelButton>
            )}
          </SectionTitle>

          {error && <ErrorMessage>{error}</ErrorMessage>}
          {success && <SuccessMessage>{success}</SuccessMessage>}

          {isEditing ? (
            <ProfileForm onSubmit={handleSubmit}>
              <FormGroup>
                <FormLabel>Name</FormLabel>
                <FormInput 
                  type="text" 
                  name="name" 
                  value={formData.name} 
                  onChange={handleChange} 
                  placeholder="Your name"
                />
              </FormGroup>

              <FormGroup>
                <FormLabel>Email</FormLabel>
                <FormInput 
                  type="email" 
                  name="email" 
                  value={formData.email} 
                  onChange={handleChange} 
                  placeholder="Your email"
                />
              </FormGroup>

              <FormGroup>
                <FormLabel>New Password (leave blank to keep current)</FormLabel>
                <FormInput 
                  type="password" 
                  name="password" 
                  value={formData.password} 
                  onChange={handleChange} 
                  placeholder="New password"
                />
              </FormGroup>

              <FormGroup>
                <FormLabel>Confirm New Password</FormLabel>
                <FormInput 
                  type="password" 
                  name="confirmPassword" 
                  value={formData.confirmPassword} 
                  onChange={handleChange} 
                  placeholder="Confirm new password"
                  disabled={!formData.password}
                />
              </FormGroup>

              <SaveButton type="submit">
                <FaSave /> Save Changes
              </SaveButton>
            </ProfileForm>
          ) : (
            <ProfileInfo>
              <InfoItem>
                <InfoLabel>Name:</InfoLabel>
                <InfoValue>{user?.name || 'Not set'}</InfoValue>
              </InfoItem>

              <InfoItem>
                <InfoLabel>Email:</InfoLabel>
                <InfoValue>{user?.email || 'Not set'}</InfoValue>
              </InfoItem>

              <InfoItem>
                <InfoLabel>Member Since:</InfoLabel>
                <InfoValue>
                  {user?.createdAt 
                    ? new Date(user.createdAt).toLocaleDateString() 
                    : 'Not available'}
                </InfoValue>
              </InfoItem>
            </ProfileInfo>
          )}
        </ProfileSection>

        <ProfileSection>
          <SectionTitle>My Ratings</SectionTitle>

          {loading ? (
            <LoadingMessage>Loading your ratings...</LoadingMessage>
          ) : ratedMovies.length > 0 ? (
            <RatedMoviesGrid>
              {ratedMovies.map(movie => (
                <RatedMovie key={movie.id} onClick={() => navigate(`/movie/${movie.id}`)}>
                  <MoviePoster src={movie.poster_path} alt={movie.title} />
                  <MovieInfo>
                    <MovieTitle>{movie.title}</MovieTitle>
                    <MovieYear>{movie.release_date?.substring(0, 4)}</MovieYear>
                    <MovieRating>
                      Your Rating: {movie.user_rating} / 5
                    </MovieRating>
                  </MovieInfo>
                </RatedMovie>
              ))}
            </RatedMoviesGrid>
          ) : (
            <EmptyMessage>You haven't rated any movies yet</EmptyMessage>
          )}
        </ProfileSection>
      </ProfileContent>
    </ProfileContainer>
  );
};

